import React from 'react';
import './Section.css';

class Section extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
        expanded: true,
    }
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick() {
      this.setState(state => ({
          expanded: !this.state.expanded,
      }));
  }

  collapse() {

  }

  render() {
    return (
      <div id='outer' onClick={() => this.handleClick()}>
          <h3>{this.props.headline}</h3>
      </div>
    );
  }
}

const Portfolio = () => {
    return (
        <div id='portfolio'>
            <Section headline='Reporting on UCLA student at the U.S. Capitol riots'/>
            <Section headline='Data reporting'/>
            <Section headline='Reporting on COVID-19 across LA County and at UCLA'/>
            <Section headline='Other daily reporting'/>
        </div>
    );
}

export default Portfolio;
